export async function seedWget() {
    try {
        console.log("Seeding tool Wget...");
        await Tool.deleteMany({ name: "Wget" });
        
        const toolDoc = new Tool(toolPayload);
        await toolDoc.save();
        
        console.log("Seeded tool Wget successfully.");
    } catch (error) {
        console.error("Seeding tool Wget failed:", error);
        throw error;
    }
}
